sql:
SELECT users.first_name, users.last_name, maps.map_name
FROM users
LEFT JOIN maps ON users.user_id = maps.user_id;

SELECT name, population, area_sq_km, median_income, average_house_price
FROM neighborhoods
WHERE borough = 'Manhattan' AND average_house_price > 500000;

SELECT name, population
FROM neighborhoods
WHERE population > (SELECT AVG(population) FROM neighborhoods);

SELECT population, median_income
FROM neighborhoods
WHERE borough = (
    SELECT name
    FROM boroughs
    WHERE median_income = (
        SELECT MAX(median_income)
        FROM boroughs
    )
);

SELECT AVG(area_sq_km) AS average_area
FROM neighborhoods
WHERE borough = 'Downtown Toronto' AND average_house_price > 1000000;

SELECT neighborhoods.name AS Neighborhood, boroughs.name AS Borough
FROM neighborhoods
INNER JOIN boroughs ON neighborhoods.borough = boroughs.name;

SELECT neighborhood_id, UPPER(name) AS neighborhood_name, average_house_price, DATE(created_at) AS creation_date
FROM neighborhoods
WHERE average_house_price > (SELECT AVG(average_house_price) FROM neighborhoods);

SELECT n.name
FROM neighborhoods n
WHERE n.average_house_price > (SELECT AVG(average_house_price) FROM neighborhoods);

external_knowledge:
Crowd density refers to population density; economically priced houses are those with prices below $1,000,000;
Decent family earnings refer to a median income greater than $50,000;
Notably dense population means the population density exceeds 1000 people per square kilometer.

